import{_ as t,o as a,c as o,a2 as s}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"Smart Routing","description":"How WebRouter intelligently routes requests to the best model","frontmatter":{"title":"Smart Routing","description":"How WebRouter intelligently routes requests to the best model"},"headers":[],"relativePath":"guide/smart-routing.md","filePath":"guide/smart-routing.md"}'),r={name:"guide/smart-routing.md"};function i(l,e,n,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="smart-routing" tabindex="-1">Smart Routing <a class="header-anchor" href="#smart-routing" aria-label="Permalink to &quot;Smart Routing&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>WebRouter&#39;s smart routing feature automatically selects the optimal model based on request complexity. Instead of hardcoding a model name, you can set <code>model: &quot;auto&quot;</code> and let WebRouter decide.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>When a request comes in with <code>model: &quot;auto&quot;</code>, WebRouter:</p><ol><li><strong>Analyzes</strong> the request — prompt length, complexity indicators, system prompt presence</li><li><strong>Scores</strong> each available model on capability vs. cost</li><li><strong>Selects</strong> the best match: simple requests get fast/cheap models, complex reasoning gets powerful ones</li><li><strong>Routes</strong> the request to the selected provider</li></ol><h2 id="model-grades" tabindex="-1">Model Grades <a class="header-anchor" href="#model-grades" aria-label="Permalink to &quot;Model Grades&quot;">​</a></h2><p>Model grades let you define tiers of model capability:</p><table tabindex="0"><thead><tr><th>Grade</th><th>Examples</th><th>Use Case</th></tr></thead><tbody><tr><td><code>premium</code></td><td>gpt-4o, claude-sonnet-4</td><td>Complex reasoning, code generation</td></tr><tr><td><code>standard</code></td><td>gpt-4o-mini, deepseek-chat</td><td>General purpose</td></tr><tr><td><code>economy</code></td><td>qwen-turbo, claude-haiku</td><td>Simple Q&amp;A, classification</td></tr></tbody></table><p>Configure model grades in <strong>Settings</strong> → <strong>Model Grades</strong>.</p><h2 id="model-aliases" tabindex="-1">Model Aliases <a class="header-anchor" href="#model-aliases" aria-label="Permalink to &quot;Model Aliases&quot;">​</a></h2><p>Create aliases for common model names:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gpt4 → gpt-4o</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">claude-sonnet → claude-sonnet-4</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">deepseek-v3 → deepseek-chat</span></span></code></pre></div><p>This allows you to use short, stable names in your application while WebRouter maps them to the actual provider model names.</p><h2 id="fallback-retry" tabindex="-1">Fallback &amp; Retry <a class="header-anchor" href="#fallback-retry" aria-label="Permalink to &quot;Fallback &amp; Retry&quot;">​</a></h2><p>When a provider fails, WebRouter automatically:</p><ol><li><strong>Retries</strong> the request with exponential backoff (up to 3 attempts)</li><li><strong>Falls back</strong> to the next available provider with the same model</li><li><strong>Smart downgrade</strong> — if configured, uses a cheaper model to complete the request</li></ol>`,17)])])}const m=t(r,[["render",i]]);export{u as __pageData,m as default};
